# CALCULATE RISK PARITY WEIGHTS
# Simple Inverse Volatility Weighting method

data = items[0].json['assets']

# 1. Calculate Inverse Volatility (1 / sigma)
inv_vols = {}
total_inv_vol = 0

for asset, vol in data.items():
    if vol == 0: vol = 0.001 # Prevent divide by zero
    inv = 1 / vol
    inv_vols[asset] = inv
    total_inv_vol += inv

# 2. Calculate Weights
weights = {}
risk_contribution = {}

for asset, inv in inv_vols.items():
    # Weight = (1/sigma) / Sum(1/sigma)
    w = inv / total_inv_vol
    weights[asset] = round(w * 100, 2)

    # Verify Risk Contribution (Weight * Vol should be roughly equal)
    # Note: True Risk Parity uses Covariance, this is 'Naive' Risk Parity
    risk_contribution[asset] = round(w * data[asset] * 100, 2)

return [{
  "json": {
    "vix_trigger": True,
    "optimal_weights": weights,
    "risk_metrics": risk_contribution,
    "interpretation": "High volatility assets (Nifty) got lower weight. Stable assets (Bonds) got higher weight."
  }
}]
